}

int binary_search(int *arr, int l, int r, int target) {
    while (l <= r) {
        int m = l + (r - l) / 2;
        if (arr[m] == target) return 1;
        if (arr[m] < target) l = m + 1; else r = m - 1;
    }
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int ok = 1; // assume AP‑Free
        for (int i = 0; i < N && ok; ++i) {
            for (int k = i + 2; k < N && ok; ++k) {
                int sum = a[i] + a[k];
                if (sum % 2) continue; // middle would be non‑integer
                int mid = sum / 2;
                if (binary_search(a, i + 1, k - 1, mid)) {
                    ok = 0; // found an AP
                }
            }
        }
        printf(ok ? "YES\n" : "NO\n");
        free(a);
    }
    return 0;
}

