#include <bits/stdc++.h>
using namespace std;

bool existsMiddle(const vector<int>& a, int i, int k) {
    long long sum = (long long)a[i] + a[k];
    if (sum & 1) return false; // not integer
    int mid = sum / 2;
    return binary_search(a.begin() + i + 1, a.begin() + k, mid);
}

int main() {
    ios::sync_with_stdio(false);
