    while(T--) {
        int N; cin>>N;
        vector<int> a(N);
        for(int &x: a) cin>>x;
        bool apFree = true;
        for(int i=0;i<N && apFree;i++){
            for(int k=i+2;k<N && apFree;k++){
                if (existsMiddle(a,i,k)) apFree = false;
            }
        }
        cout << (apFree?"YES":"NO") << '\n';
    }
    return 0;
}

