#!/usr/bin/env python3
import sys

def is_ap_free(arr):
    n = len(arr)
    for i in range(n):
        for k in range(i + 2, n):
            s = arr[i] + arr[k]
            if s & 1:
                continue
            mid = s // 2
            # binary search in arr[i+1:k]
            lo, hi = i + 1, k - 1
            while lo <= hi:
                m = (lo + hi) // 2
                if arr[m] == mid:
                    return False
                if arr[m] < mid:
                    lo = m + 1
                else:
                    hi = m - 1
    return True

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out_lines.append('YES' if is_ap_free(arr) else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

